import 'package:flutter/material.dart';
import 'package:webview_flutter/webview_flutter.dart';
import 'dart:convert';
import 'package:image_picker/image_picker.dart';
import 'package:firebase_messaging/firebase_messaging.dart';
import 'package:permission_handler/permission_handler.dart';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  runApp(MyApp());
}

class MyApp extends StatelessWidget {
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'WebView Hybrid App',
      theme: ThemeData(
        primarySwatch: Colors.blue,
      ),
      home: WebViewScreen(),
    );
  }
}

class WebViewScreen extends StatefulWidget {
  @override
  _WebViewScreenState createState() => _WebViewScreenState();
}

class _WebViewScreenState extends State<WebViewScreen> {
  late WebViewController _controller;
  final ImagePicker _imagePicker = ImagePicker();
  FirebaseMessaging? _firebaseMessaging;
  String? _fcmToken;

  @override
  void initState() {
    super.initState();
    _initializePushNotifications();
  }

  Future<void> _initializePushNotifications() async {
    try {
      _firebaseMessaging = FirebaseMessaging.instance;

      NotificationSettings settings = await _firebaseMessaging!.requestPermission(
        alert: true,
        badge: true,
        sound: true,
      );

      if (settings.authorizationStatus == AuthorizationStatus.authorized) {
        _fcmToken = await _firebaseMessaging!.getToken();
        print('FCM Token: $_fcmToken');

        FirebaseMessaging.onMessage.listen((RemoteMessage message) {
          _handleNotification(message);
        });

        FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {
          _handleNotification(message);
        });
      }
    } catch (e) {
      print('Error initializing push notifications: $e');
    }
  }

  void _handleNotification(RemoteMessage message) {
    String notificationData = jsonEncode({
      'title': message.notification?.title ?? '',
      'body': message.notification?.body ?? '',
      'data': message.data,
    });

    _controller.runJavaScript(
      "window.dispatchEvent(new CustomEvent('flutterNotification', { detail: $notificationData }));",
    );
  }

  Future<void> _openCamera() async {
    var status = await Permission.camera.request();
    if (status.isGranted) {
      final XFile? photo = await _imagePicker.pickImage(source: ImageSource.camera);
      if (photo != null) {
        String imagePath = photo.path;
        _controller.runJavaScript(
          "window.dispatchEvent(new CustomEvent('cameraImage', { detail: '$imagePath' }));",
        );
      }
    } else {
      _controller.runJavaScript(
        "window.dispatchEvent(new CustomEvent('cameraError', { detail: 'Camera permission denied' }));",
      );
    }
  }

  Future<void> _pickImageFromGallery() async {
    var status = await Permission.photos.request();
    if (status.isGranted || status.isLimited) {
      final XFile? image = await _imagePicker.pickImage(source: ImageSource.gallery);
      if (image != null) {
        String imagePath = image.path;
        _controller.runJavaScript(
          "window.dispatchEvent(new CustomEvent('galleryImage', { detail: '$imagePath' }));",
        );
      }
    } else {
      _controller.runJavaScript(
        "window.dispatchEvent(new CustomEvent('galleryError', { detail: 'Gallery permission denied' }));",
      );
    }
  }

  Future<void> _requestNotificationPermission() async {
    var status = await Permission.notification.request();
    bool granted = status.isGranted;
    _controller.runJavaScript(
      "window.dispatchEvent(new CustomEvent('notificationPermission', { detail: $granted }));",
    );
  }

  Future<String> _getFCMToken() async {
    return _fcmToken ?? '';
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(
        title: Text('Hybrid WebView App'),
        actions: [
          IconButton(
            icon: Icon(Icons.refresh),
            onPressed: () {
              _controller.reload();
            },
          ),
        ],
      ),
      body: WebView(
        initialUrl: 'https://your-mobile-website.com',
        javascriptMode: JavascriptMode.unrestricted,
        onWebViewCreated: (WebViewController webViewController) {
          _controller = webViewController;
        },
        javascriptChannels: <JavascriptChannel>{
          JavascriptChannel(
            name: 'FlutterChannel',
            onMessageReceived: (JavascriptMessage message) {
              _handleJavascriptMessage(message.message);
            },
          ),
        },
        onPageFinished: (String url) {
          _injectJavaScript();
        },
        gestureNavigationEnabled: true,
      ),
    );
  }

  void _injectJavaScript() {
    String jsCode = """
      window.flutterBridge = {
        openCamera: function() {
          FlutterChannel.postMessage(JSON.stringify({ action: 'openCamera' }));
        },
        pickImage: function() {
          FlutterChannel.postMessage(JSON.stringify({ action: 'pickImage' }));
        },
        requestNotificationPermission: function() {
          FlutterChannel.postMessage(JSON.stringify({ action: 'requestNotificationPermission' }));
        },
        getFCMToken: function(callback) {
          window.fcmTokenCallback = callback;
          FlutterChannel.postMessage(JSON.stringify({ action: 'getFCMToken' }));
        },
        showToast: function(message) {
          FlutterChannel.postMessage(JSON.stringify({ action: 'showToast', data: message }));
        }
      };
      console.log('Flutter bridge initialized');
    """;

    _controller.runJavaScript(jsCode);
  }

  void _handleJavascriptMessage(String message) {
    try {
      Map<String, dynamic> data = jsonDecode(message);
      String action = data['action'];

      switch (action) {
        case 'openCamera':
          _openCamera();
          break;
        case 'pickImage':
          _pickImageFromGallery();
          break;
        case 'requestNotificationPermission':
          _requestNotificationPermission();
          break;
        case 'getFCMToken':
          _getFCMToken().then((token) {
            _controller.runJavaScript(
              "if (window.fcmTokenCallback) window.fcmTokenCallback('$token');",
            );
          });
          break;
        case 'showToast':
          String toastMessage = data['data'] ?? 'Message';
          ScaffoldMessenger.of(context).showSnackBar(
            SnackBar(content: Text(toastMessage)),
          );
          break;
        default:
          print('Unknown action: $action');
      }
    } catch (e) {
      print('Error handling JavaScript message: $e');
    }
  }
}